import { useState } from 'react';

export type SimpleTableHookProps<TData> = {
  data: TData[];
  defaultPageSize?: number;
};

export function useSimpleTable<TData>({ data, defaultPageSize = 10 }: SimpleTableHookProps<TData>) {
  const [pageSize, setPageSize] = useState(defaultPageSize);
  const [currentPage, setCurrentPage] = useState(1);

  function onPageSizeChange(newPageSize: string) {
    setPageSize(Number(newPageSize));
    setCurrentPage(1);
  }

  function onCurrentPageChange(newCurrentPage: number) {
    setCurrentPage(newCurrentPage);
  }

  function getPageSize() {
    return `${pageSize}`;
  }

  function getTotalPage() {
    return data.length === 0 ? 1 : Math.ceil(data.length / pageSize);
  }

  function getCurrentPage() {
    return currentPage;
  }

  function getCurrentPageData() {
    return data.slice(pageSize * (currentPage - 1), pageSize * currentPage);
  }

  function toFirstPage() {
    onCurrentPageChange(1);
  }

  function disableFirstPage() {
    return getCurrentPage() === 1;
  }

  function toLastPage() {
    onCurrentPageChange(getTotalPage());
  }

  function disableLastPage() {
    return getCurrentPage() === getTotalPage();
  }

  function toPrevPage() {
    onCurrentPageChange(getCurrentPage() - 1);
  }

  function disablePrevPage() {
    return getCurrentPage() === 1;
  }

  function toNextPage() {
    onCurrentPageChange(getCurrentPage() + 1);
  }

  function disableNextPage() {
    return getCurrentPage() === getTotalPage();
  }

  return {
    onPageSizeChange,
    getPageSize,
    getTotalPage,
    getCurrentPage,
    getCurrentPageData,
    toFirstPage,
    disableFirstPage,
    toLastPage,
    disableLastPage,
    toPrevPage,
    disablePrevPage,
    toNextPage,
    disableNextPage,
  };
}
